import java.util.*;
public class SetBasics {
    public static void main(String[] a){
        Set<Integer> set=new HashSet<>(Arrays.asList(1,2,3,4,5));
        System.out.println(set.contains(3));    // true  O(1)
        System.out.println(set.contains(6));    // false O(1)
        set.add(6); set.remove(1);
        System.out.println(set.size());         // 5
        System.out.println("HashSet: O(1) add/remove/contains — backed by HashMap");
        System.out.println("LinkedHashSet: O(1) + insertion order");
        System.out.println("TreeSet: O(log n) + sorted order");
    }
}

import java.util.*;
public class ContainsDup {
    public static boolean containsDuplicate(int[] nums) {
        Set<Integer> seen=new HashSet<>();
        for(int n:nums) if(!seen.add(n)) return true;
        return false;
    }
    public static void main(String[] a){
        System.out.println(containsDuplicate(new int[]{1,2,3,1})); // true
        System.out.println(containsDuplicate(new int[]{1,2,3,4})); // false
        System.out.println("add() returns false if already present — elegant one-liner");
    }
}

import java.util.*;
public class SetOps {
    static int[] intersection(int[] a, int[] b){
        Set<Integer> s=new HashSet<>();for(int x:a)s.add(x);
        Set<Integer> res=new HashSet<>();for(int x:b)if(s.contains(x))res.add(x);
        return res.stream().mapToInt(Integer::intValue).toArray();
    }
    static int[] union(int[] a, int[] b){
        Set<Integer> s=new HashSet<>();for(int x:a)s.add(x);for(int x:b)s.add(x);
        return s.stream().mapToInt(Integer::intValue).toArray();
    }
    public static void main(String[] a){
        System.out.println(intersection(new int[]{1,2,2,1},new int[]{2,2}).length); // 1
        System.out.println(union(new int[]{1,2},new int[]{2,3}).length); // 3
        System.out.println("O(n+m) — HashSet for O(1) contains");
    }
}

import java.util.*;
public class Jewels {
    public static int numJewelsInStones(String jewels, String stones) {
        Set<Character> j=new HashSet<>();for(char c:jewels.toCharArray())j.add(c);
        int count=0; for(char c:stones.toCharArray()) if(j.contains(c)) count++;
        return count;
    }
    public static void main(String[] a){
        System.out.println(numJewelsInStones("aA","aAAbbbb")); // 3
        System.out.println(numJewelsInStones("z","ZZ"));       // 0
        System.out.println("O(j+s) — HashSet for jewel lookup");
    }
}

import java.util.*;
public class DupII {
    public static boolean containsNearbyDuplicate(int[] nums, int k) {
        Set<Integer> window=new HashSet<>();
        for(int i=0;i<nums.length;i++){
            if(window.contains(nums[i])) return true;
            window.add(nums[i]);
            if(window.size()>k) window.remove(nums[i-k]);
        }
        return false;
    }
    public static void main(String[] a){
        System.out.println(containsNearbyDuplicate(new int[]{1,2,3,1},3)); // true
        System.out.println(containsNearbyDuplicate(new int[]{1,0,1,1},1)); // true
        System.out.println(containsNearbyDuplicate(new int[]{1,2,3,1,2,3},2)); // false
        System.out.println("Sliding HashSet window of size k: O(n) O(k)");
    }
}

import java.util.*;
public class FirstMissing {
    public static int firstMissingPositive(int[] nums) {
        Set<Integer> set=new HashSet<>();for(int n:nums)set.add(n);
        for(int i=1;i<=nums.length+1;i++) if(!set.contains(i)) return i;
        return nums.length+1;
    }
    public static void main(String[] a){
        System.out.println(firstMissingPositive(new int[]{1,2,0}));    // 3
        System.out.println(firstMissingPositive(new int[]{3,4,-1,1})); // 2
        System.out.println(firstMissingPositive(new int[]{7,8,9,11})); // 1
        System.out.println("O(n) O(n) — HashSet approach. O(n) O(1): index marking trick");
    }
}

import java.util.*;
public class LCS2 {
    public static int longestConsecutive(int[] nums) {
        Set<Integer> set=new HashSet<>();for(int n:nums)set.add(n);
        int best=0;
        for(int n:set){if(!set.contains(n-1)){int len=1;while(set.contains(n+len))len++;best=Math.max(best,len);}}
        return best;
    }
    public static void main(String[] a){
        System.out.println(longestConsecutive(new int[]{100,4,200,1,3,2}));    // 4
        System.out.println(longestConsecutive(new int[]{0,3,7,2,5,8,4,6,0,1})); // 9
        System.out.println("O(n) — only start sequence from n where n-1 not in set");
    }
}

import java.util.*;
public class CycleHash {
    static class Node{int val;Node next;Node(int v){val=v;}}
    public static boolean hasCycle(Node head) {
        Set<Node> seen=new HashSet<>();
        while(head!=null){if(!seen.add(head)) return true;head=head.next;}
        return false;
    }
    public static void main(String[] a){
        Node n=new Node(1);n.next=new Node(2);n.next.next=new Node(3);n.next.next.next=n.next;
        System.out.println(hasCycle(n)); // true
        System.out.println(hasCycle(new Node(1))); // false
        System.out.println("O(n) O(n) — HashSet vs O(n) O(1) Floyd. Use Floyd for O(1) space.");
    }
}

import java.util.*;
public class PathSumHash {
    static class TreeNode{int val;TreeNode left,right;TreeNode(int v){val=v;}}
    static boolean found=false;
    public static boolean hasPathSum(TreeNode root, int target) {
        Set<Integer> sums=new HashSet<>();sums.add(0);found=false;
        dfs(root,0,target,sums); return found;
    }
    static void dfs(TreeNode n, int curr, int target, Set<Integer> prevSums){
        if(n==null||found) return;
        curr+=n.val;
        if(prevSums.contains(curr-target)&&n.left==null&&n.right==null){found=true;return;}
        prevSums.add(curr);dfs(n.left,curr,target,prevSums);dfs(n.right,curr,target,prevSums);prevSums.remove(curr);
    }
    // Simpler direct:
    static boolean pathSum(TreeNode n,int rem){if(n==null)return false;rem-=n.val;if(n.left==null&&n.right==null)return rem==0;return pathSum(n.left,rem)||pathSum(n.right,rem);}
    public static void main(String[] a){
        TreeNode r=new TreeNode(5);r.left=new TreeNode(4);r.right=new TreeNode(8);r.left.left=new TreeNode(11);r.left.left.left=new TreeNode(7);r.left.left.right=new TreeNode(2);
        System.out.println(pathSum(r,22)); // true (5+4+11+2)
        System.out.println(pathSum(r,27)); // false
        System.out.println("O(n) DFS — subtract from target each level");
    }
}

import java.util.*;
public class DecodeMsg {
    public static String decodeMessage(String key, String message) {
        Map<Character,Character> cipher=new LinkedHashMap<>();char next='a';
        for(char c:key.toCharArray()){if(c!=' '&&!cipher.containsKey(c)){cipher.put(c,next);next++;}}
        StringBuilder sb=new StringBuilder();
        for(char c:message.toCharArray()) sb.append(c==' '?' ':cipher.get(c));
        return sb.toString();
    }
    public static void main(String[] a){
        System.out.println(decodeMessage("the quick brown fox jumps over the lazy dog","vkbs bs t suepuv"));
        System.out.println("this is a secret");
        System.out.println("O(k+m) — LinkedHashMap preserves insertion order for cipher");
    }
}

import java.util.*;
public class HappyHS {
    static int sumSq(int n){int s=0;while(n>0){int d=n%10;s+=d*d;n/=10;}return s;}
    public static boolean isHappy(int n){
        Set<Integer> seen=new HashSet<>();
        while(n!=1){if(!seen.add(n)) return false;n=sumSq(n);}
        return true;
    }
    public static void main(String[] a){
        System.out.println(isHappy(19)); // true
        System.out.println(isHappy(2));  // false
        System.out.println("HashSet approach: O(log n) space per unique value");
        System.out.println("Floyd approach: O(1) space — preferred");
    }
}

import java.util.*;
public class SetSynth {
    static boolean hasDup(int[] n){Set<Integer> s=new HashSet<>();for(int x:n)if(!s.add(x))return true;return false;}
    static int longConsec(int[] n){Set<Integer> s=new HashSet<>();for(int x:n)s.add(x);int b=0;for(int x:s){if(!s.contains(x-1)){int l=1;while(s.contains(x+l))l++;b=Math.max(b,l);}}return b;}
    static int[] inter(int[] a,int[] b){Set<Integer> sa=new HashSet<>();for(int x:a)sa.add(x);Set<Integer> r=new HashSet<>();for(int x:b)if(sa.contains(x))r.add(x);return r.stream().mapToInt(Integer::intValue).toArray();}
    public static void main(String[] a){
        System.out.println(hasDup(new int[]{1,2,3,1}));
        System.out.println(longConsec(new int[]{100,4,200,1,3,2}));
        System.out.println(inter(new int[]{1,2,3},new int[]{2,3,4}).length);
        boolean ok=hasDup(new int[]{1,2,3,1})&&longConsec(new int[]{100,4,200,1,3,2})==4&&inter(new int[]{1,2,3},new int[]{2,3,4}).length==2;
        System.out.println("All pass: "+ok);
    }
}

import java.util.*;
public class T3Final {
    static boolean hasDup(int[] n){Set<Integer> s=new HashSet<>();for(int x:n)if(!s.add(x))return true;return false;}
    static boolean nearDup(int[] n,int k){Set<Integer> w=new HashSet<>();for(int i=0;i<n.length;i++){if(w.contains(n[i]))return true;w.add(n[i]);if(w.size()>k)w.remove(n[i-k]);}return false;}
    static int longConsec(int[] n){Set<Integer> s=new HashSet<>();for(int x:n)s.add(x);int b=0;for(int x:s){if(!s.contains(x-1)){int l=1;while(s.contains(x+l))l++;b=Math.max(b,l);}}return b;}
    static int firstMissing(int[] n){Set<Integer> s=new HashSet<>();for(int x:n)s.add(x);for(int i=1;;i++)if(!s.contains(i))return i;}
    public static void main(String[] a){
        System.out.println("hasDup="+hasDup(new int[]{1,2,3,1}));
        System.out.println("nearDup="+nearDup(new int[]{1,2,3,1},3));
        System.out.println("longConsec="+longConsec(new int[]{100,4,200,1,3,2}));
        System.out.println("firstMissing="+firstMissing(new int[]{3,4,-1,1}));
        boolean ok=hasDup(new int[]{1,2,3,1})&&nearDup(new int[]{1,2,3,1},3)&&longConsec(new int[]{100,4,200,1,3,2})==4&&firstMissing(new int[]{3,4,-1,1})==2;
        System.out.println("All pass: "+ok);
    }
}
